#pragma OPENCL EXTENSION cl_khr_fp64 : enable
#define THREADS_PER_DIM 16
#define BLOCKS_PER_DIM 16
#define THREADS_PER_BLOCK (THREADS_PER_DIM*THREADS_PER_DIM)

#define ASSUMED_NR_CLUSTERS 32
#define FLT_MAX 3.40282347e+38f

__constant float c_clusters[ASSUMED_NR_CLUSTERS*34];

__kernel void invert_mapping(__global float *input,
                             __global float *output,
                             const int npoints,
                             const int nfeatures)
{
    int point_id = get_global_id(0);
    if(point_id < npoints){
        for(int i=0; i<nfeatures; i++){
            output[point_id + npoints*i] = input[point_id*nfeatures + i];
        }
    }
}

__kernel void kmeansPoint(__global float  *features,
                          const int nfeatures,
                          const int npoints,
                          const int nclusters,
                          __global int    *membership,
                          __global float  *clusters,
                          __global float  *block_clusters,
                          __global int    *block_deltas)
{
    int gridDimX = get_num_groups(0);
    int gridDimY = get_num_groups(1);
    int blockIdxX = get_group_id(0);
    int blockIdxY = get_group_id(1);
    int threadIdxX = get_local_id(0);
    int blockDimX = get_local_size(0);
    int blockDimY = 1; // original CUDA uses 1D block in y?

    const unsigned int block_id = gridDimX*blockIdxY + blockIdxX;
    const unsigned int point_id = block_id * blockDimX * blockDimY + threadIdxX;

    int index = -1;

    if (point_id < npoints)
    {
        float min_dist = FLT_MAX;
        for (int i=0; i<nclusters; i++) {
            int cluster_base_index = i * nfeatures;
            float ans = 0.0f;
            for (int j=0; j<nfeatures; j++) {
                int addr = point_id + j * npoints;
                float diff = features[addr] - c_clusters[cluster_base_index + j];
                ans += diff*diff;
            }
            float dist = ans;
            if (dist < min_dist){
                min_dist = dist;
                index = i;
            }
        }
    }

    // GPU_DELTA_REDUCTION equivalent
    __local int deltas[THREADS_PER_BLOCK];
    if(threadIdxX < THREADS_PER_BLOCK){
        deltas[threadIdxX] = 0;
    }
    barrier(CLK_LOCAL_MEM_FENCE);

    if (point_id < npoints)
    {
        if (membership[point_id] != index) {
            deltas[threadIdxX] = 1;
        }
        membership[point_id] = index;
    }

    barrier(CLK_LOCAL_MEM_FENCE);

    // Parallel reduction in local memory for deltas
    unsigned int s = THREADS_PER_BLOCK / 2;
    while (s > 0) {
        if (threadIdxX < s) {
            deltas[threadIdxX] += deltas[threadIdxX + s];
        }
        barrier(CLK_LOCAL_MEM_FENCE);
        s = s / 2;
    }

    if (threadIdxX == 0) {
        block_deltas[blockIdxY * gridDimX + blockIdxX] = deltas[0];
    }

    // GPU_NEW_CENTER_REDUCTION equivalent
    int center_id = threadIdxX / nfeatures;
    int dim_id = threadIdxX - nfeatures * center_id;

    __local int new_center_ids[THREADS_PER_BLOCK];
    new_center_ids[threadIdxX] = index;
    barrier(CLK_LOCAL_MEM_FENCE);

    if(threadIdxX < nfeatures * nclusters) {
        int base_point_id = (point_id - threadIdxX);
        float accumulator = 0.f;
        for(int i = 0; i < THREADS_PER_BLOCK; i++) {
            int new_center_id = new_center_ids[i];
            float val = features[base_point_id + i * nfeatures];
            if(new_center_id == center_id) {
                accumulator += val;
            }
        }
        int block_index = (blockIdxY * gridDimX + blockIdxX);
        block_clusters[block_index * nclusters * nfeatures + threadIdxX] = accumulator;
    }
}
